import type {
  QrSignPayload,
  SignedQrToken,
} from '../../domain/factories/qr-ticket.factory';

/**
 * QR token signer port (README §2.3 QR / §2.8 Workflow 1 step 2).
 * Implemented by the infrastructure `JwtQrSigner` (HS256). The application and
 * the domain factory both depend on this shape; the concrete signer wraps
 * `jsonwebtoken`. Verification returns the decoded claims or throws a typed
 * `QrTokenExpiredError` / `InvalidQrTokenError`.
 */
export const QR_SIGNER = 'IQrSigner';

export interface QrTokenClaims {
  sessionId: string;
  itemHash: string;
  userId: string;
  /** Standard JWT expiry (seconds since epoch). */
  exp: number;
}

export interface IQrSigner {
  sign(payload: QrSignPayload): SignedQrToken;
  verify(token: string): QrTokenClaims;
}
